    ('MUS-M 620', 'DOCTORAL FINAL PROJECT', '2405', 'Class Status', NULL, NULL, 'David Cartledge', 56, NULL, 'Independent Study', '1–8', NULL, ARRAY[]::TEXT[], 'Document or essay for performance doctoral degrees.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 621', 'DOCTORAL PIANO ESSAY', '3579', 'Class Status', NULL, NULL, 'David Cartledge', 82, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Required essay for DM Piano degree.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 627', 'INDEPENDENT STUDY OF THE LITERATURE OF THE GUITAR I', '7719', 'Class Status', NULL, NULL, 'Petar Jankovic', 9, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Survey of guitar literature to 1800. Two papers will be required.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 628', 'INDEPENDENT STUDY OF THE LITERATURE OF THE GUITAR II', '7720', 'Class Status', NULL, NULL, 'Petar Jankovic', 6, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Survey of guitar literature since 1800. Two papers will be required.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 633', 'WIND LITERATURE AND PEDAGOGY FOR COLLABORATIVE PIANISTS', '33877', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'JS 315', 'Anne Epperson, Aram Arakelyan', 1, NULL, 'Lecture', '3', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'A practical, analytical, and historical study of relevant woodwind and brass repertoire. Emphasis on sonata/duo, concerti and French conservatory pieces. Exploration of the pedagogical value of certain repertoire, the nature of the instruments and their pedagogy, and how these principles can be adapted to pianists.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 635', 'PERFORMANCE PRACT BEFORE 1750', '10948', 'Closed', 'MW Monday, Wednesday 10:10 AM–11:00 AM', 'MU 204', 'Joanna Blendulf', 0, NULL, 'Lecture', '2', 'MERRILL HALL', ARRAY[]::TEXT[], 'Styles of solo and ensemble performance of instrumental and vocal music from the Middle Ages through the Baroque period: medium, dynamics, tempo, ornamentation and improvisation, temperament. Editing and performing of works for old and modern instruments.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 637', 'SEMINAR IN PERCUSSION HISTORY', '2406', 'Class Status', NULL, NULL, 'John Tafoya', 1, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], 'A survey of masterworks. The origin, development, and influences of indigenous instruments and their uses in 20th-century music.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 640', 'SELECTED TOPICS IN ORGAN LITERATURE AND PERFORMANCE PRACTICE', '36473', 'Class Status', 'M Monday 4:20 PM–6:00 PM', 'JS 222', 'Janette Fishell', 5, NULL, 'Lecture', '2', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'An advanced graduate seminar that gives an in-depth exploration of a genre, period, or composer(s) of seminal importance to the organist''s repertoire through instructor-mentored group discussion of required readings, score study and listening.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 642', 'BRASS LITERATURE 2', '34164', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–11:05 AM', 'JS 306', 'Richard Seraphinoff', 0, NULL, 'Lecture', '3', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'Solo and chamber music literature for horn, trumpet, trombone, euphonium, and tuba. Development of brass instruments and literature from Renaissance to the present. Survey of sources providing announcement and evaluation of new materials.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 647', 'SEMINAR IN PIANO LITERATURE III', '33880', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'MA 405', 'David Cartledge, Emile Naoumoff', 8, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Discussion of historical, stylistic, formal and aesthetic aspects of the Romantic period from Schumann through Brahms; performance of representative works from 1830-1900.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 650', 'MUSIC IN THE UNITED STATES', '14564', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'MU 205', 'Philip Ford', 0, NULL, 'Lecture', '3', 'MERRILL HALL', ARRAY[]::TEXT[], 'A musical and cultural history emphasizing the co-existence and intersections of a variety of imported and indigenous, written and oral, traditions, including concert music, opera, Native American music, popular song, jazz, blues, musical theater and film, Tin Pan Alley, rock, spirituals and other religious idioms.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 653', 'BAROQUE MUSIC', '6949', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'MU 204', 'Devon Nelson', 0, NULL, 'Lecture', '3', 'MERRILL HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-M 655', 'ROMANTIC MUSIC', '2407', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SM 344', 'Halina Goldberg', 2, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-M 661', 'DOCTORAL SEMINAR IN CHORAL LITERATURE: RENAISSANCE TO 1700', '30305', 'Class Status', 'MW Monday, Wednesday 11:35 AM–1:05 PM', 'SM 271', 'Carolann Buff', 8, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An analytical and contextual study of choral repertoire from liturgical beginnings through the early Baroque.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 665', 'SURVEY OF VIOLIN/VIOLA LITERATURE I. BAROQUE AND CLASS', '11484', 'Closed', 'Th Thursday 11:35 AM–12:25 PM', 'MC 040', 'Ingrid Matthews', 0, NULL, 'Lecture', '2', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-M 669', 'SEMINAR IN STRING QUARTET LITERATURE', '6322', 'Class Status', 'Tu Tuesday 12:45 PM–2:00 PM', 'JS 315', 'Simin Ganatra', 12, NULL, 'Lecture', '2', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'Performance-based survey of chamber music literature from Haydn to the present. Six seminal works covered each semester.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 671', 'DOCTORAL SEMINAR IN SYMPHONIC LITERATURE', '12311', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:25 AM', 'MA 405', 'Arthur Fagen, Jeff Meyer, Thomas Wilkins', 11, NULL, 'Seminar', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Advanced critical examination of scores, rehearsal methods, conducting technique, and interpretation.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 679', 'DOCTORAL SEMINAR IN WIND LITERATURE', '13445', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SM 153A', 'Donald McKinney', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Historical and analytical study of major wind literature.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 686', 'SOLO VOCAL LITERATURE BEFORE 1850', '34400', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'MA 007', 'Allan Armstrong', 0, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Discussion of British songs with keyboard by Purcell and Blow, lieder from Mozart through Schumann, French mélodie before Fauré, songs by Italian bel canto composers, and the early Russian romance. Special attention to identifying repertoire appropriate for teaching undergraduates and professional recitals. Creation of annotated bibliography and repertoire listening logs.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 698', 'INDIV SEMINAR IN MUSICOLOGY', '2408', 'Class Status', NULL, NULL, 'Jennifer Saltzstein', 5, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], 'For advanced students in musicology and music theory; formal research paper required.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 700', 'DISSERTATION IN MUSICOLOGY', '2409', 'Class Status', NULL, NULL, 'David Cartledge', 31, NULL, 'Independent Study', '1–15', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-N 399', 'HONORS SEMINAR IN MUSIC', '4736', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'MA 006', 'Amy Ming Wai Tai', 2, NULL, 'Seminar', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Admission to the School of Music undergraduate honors program. Reading and discussion in special topics, ranging from performance practice to music and culture.', ARRAY[]::TEXT[], NULL),
    ('MUS-N 399', 'HONORS SEMINAR IN MUSIC', '30561', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'MA 006', 'James Donaldson', 8, NULL, 'Seminar', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Admission to the School of Music undergraduate honors program. Reading and discussion in special topics, ranging from performance practice to music and culture.', ARRAY[]::TEXT[], NULL),
    ('MUS-N 499', 'HONORS PROJECT IN MUSIC', '2411', 'Class Status', NULL, NULL, 'Kyle Adams', 4, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-N 561', 'MIDI AND COMPUTER MUSIC', '6366', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'SM 373', 'Chi Wang', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Basics of the Musical Instrument Digital Interface system, its software, and instruments commonly used with desktop MIDI workstations (synthesizers, digital samplers). In-depth study of MIDI sequencing, digital audio editing, and the architecture of electronic instruments. A final project and a paper on a computer music topic is required.', ARRAY[]::TEXT[], NULL),
    ('MUS-N 561', 'MIDI AND COMPUTER MUSIC', '6367', 'Closed', 'MW Monday, Wednesday 10:25 AM–11:15 AM', 'SM 373', 'John Gibson', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Basics of the Musical Instrument Digital Interface system, its software, and instruments commonly used with desktop MIDI workstations (synthesizers, digital samplers). In-depth study of MIDI sequencing, digital audio editing, and the architecture of electronic instruments. A final project and a paper on a computer music topic is required.', ARRAY[]::TEXT[], NULL),
    ('MUS-O 101', 'FUNDAMENTALS OF JAZZ THEORY', '5481', 'Class Status', 'MW Monday, Wednesday 9:10 AM–10:00 AM', 'SM 242', 'Jeremy Allen', 6, NULL, 'Lecture', '1', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Jazz nomenclature, chord/scale relationships, basic chord progressions and voice leading. Examples from both jazz and classical repertoire will be given to show connections between the two idioms.', ARRAY[]::TEXT[], NULL),
