    ('MUS-O 213', 'JAZZ LISTENING', '9647', 'Class Status', 'TuTh Tuesday, Thursday 3:00 PM–4:15 PM', 'SM 340', 'Luke Gillespie', 3, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Introduction to basic skills required of the jazz musician, including listening, ear training, and transcription of jazz solos and their stylistic analysis.', ARRAY[]::TEXT[], NULL),
    ('MUS-O 316', 'JAZZ ARRANGING 1', '3931', 'Class Status', 'MW Monday, Wednesday 3:10 PM–4:00 PM', 'MU 204', 'Brent Wallarab', 1, NULL, 'Lecture', '2', 'MERRILL HALL', ARRAY[]::TEXT[], 'Fundamentals of jazz arranging for small ensemble including orchestration, instrument ranges and transposition, form and structure, nomenclature, and part/score layout.', ARRAY[]::TEXT[], NULL),
    ('MUS-O 322', 'JAZZ IMPROVISATION 2', '3932', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'MC 070', 'Luke Gillespie', 2, NULL, 'Lecture', '2', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Theory and technique of bebop and post-bop. Theory and techniques of jazz improvisation, including bebop and hard-bop harmonic, melodic, and rhythmic devices. Practice and study techniques and aural skills in the bebop and hard-bop styles.', ARRAY[]::TEXT[], NULL),
    ('MUS-O 323', 'JAZZ IMPROVISATION 3', '6674', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'MA 378', 'John Raymond', 17, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Advanced jazz rhythmic and harmonic techniques applied to improvisation and compositions for improvisation: contemporary jazz rhythmic practices such as note grouping, odd meters, and metric modulation applied to standard tunes. Harmonic substitution, superimposition, and slash chords. Various post-bebop approaches to improvisation.', ARRAY[]::TEXT[], NULL),
