    ('MUS-R 410', 'DRAMATIC COACHING', '34637', 'Closed', NULL, NULL, 'Michael Shell', 0, NULL, 'Activity', '1–2', NULL, ARRAY[]::TEXT[], 'The goal of this course is to learn a process for dramatic analysis of any genre of vocal performance. The focus of each session will be on the personalization of the student''s acting method skills and the fine-tuning of their application for role preparation, auditions, recitals, and other performances.', ARRAY[]::TEXT[], NULL),
    ('MUS-R 474', 'OPERA WORKSHOP', '13694', 'Closed', 'MWF Monday, Wednesday, Friday 1:30 PM–2:45 PM', 'MC 301', 'Michael Shell', 0, NULL, 'Lecture', '3', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'This class will include basic stage movement for opera singers, audition preparation, acting exercises, and work on how to research and build a character. Students will be assigned repertoire (approved by their studio teachers), and prepare operatic scenes and arias for a public performance at the end of the semester.', ARRAY[]::TEXT[], NULL),
